// ============================================================================
// QGIS 4.2 LTR MIGRATIONS-AUDIT (PHASE 2: DEFENSIVE PROGRAMMIERUNG)
// ============================================================================

let outputJson = {};

try {
  // 1. INPUT-NORMALISIERUNG MIT NULL-POINTER-SCHUTZ
  const rawItem = ($input.first && $input.first().json) || (typeof items !== 'undefined' && items[0] ? items[0].json : {});
  const item = rawItem.body || rawItem || {};  

  const auditMode = String(item.audit_modus || item.audit_mode || 'anonym').toLowerCase();
  const isAnonymous = auditMode === 'anonym' || auditMode === 'anonymous';

  const userName = item.user_name || 'Sehr geehrte(r) Anwender(in)';
  const userEmail = item.user_email || 'Nicht angegeben';
  const userOrg = item.user_org || item.organization || 'Ihre Organisation';
  const userRole = item.user_role || 'GIS-Verantwortliche(r)';

  // Robuste Auslesung mit Fallbacks gegen undefined/null
  const os = String(item.operating_system || '');
  const seats = Number(item.gis_seats) > 0 ? Number(item.gis_seats) : 1;
  const gpu = String(item.gpu_type || '');
  const qgisVer = String(item.current_qgis_version || '');
  const gdiComp = Array.isArray(item.gdi_components) ? item.gdi_components : [];
  const hasPython = String(item.has_python || '').toLowerCase();
  const pythonDetails = item.python_details || 'Keine Details angegeben.';
  const itRestrictions = item.it_restrictions || 'Keine besonderen IT-Restriktionen angegeben.';

  // 2. SCORING LOGIK (Start bei 20 Punkten)
  let score = 20;
  let riskFactors = [];
  let recommendations = [];

  // GPU / Hardware Check (Qt6 Rendering)
  if (gpu === 'onboard' || gpu.includes('Onboard')) {
    score -= 5;
    riskFactors.push('Onboard-Grafikkarte (Intel HD/UHD): Performance-Engpass bei Qt6-Rendering möglich.');
    recommendations.push('Prüfung der Hardware-Ausstattung: Aufrüstung auf dedizierte GPUs für intensive GIS-Arbeitsplätze empfohlen.');
  } else if (gpu === 'vgpu' || gpu.includes('Virtuelle')) {
    score -= 3;
    riskFactors.push('Virtuelle Umgebung (Citrix/vGPU): Besondere Grafiktreiber-Konfiguration für Qt6 erforderlich.');
    recommendations.push('Virtuelle Umgebung in Test-Image für QGIS 4 vorab evaluieren.');
  } else if (gpu === 'unknown' || gpu.includes('Unbekannt')) {
    score -= 2;
    riskFactors.push('Hardware-Infrastruktur unklar: Prüfung der GPU-Kompatibilität erforderlich.');
  }

  // Betriebssystem
  if (os.includes('Windows 10')) {
    score -= 2;
    riskFactors.push('Windows 10 Parallel-Migration: Support-Ende von Windows 10 beachten.');
  }

  // QGIS Alt-Versionen
  if (qgisVer === 'qgis_2x' || qgisVer.includes('2.x')) {
    score -= 6;
    riskFactors.push('Sehr alte QGIS 2.x Basis: Extrem hoher Migrationsabstand, Projekt-Dateien nicht direkt kompatibel.');
    recommendations.push('Mehrstufigen Migrationspfad (Projekt-Konvertierung über QGIS 3.34 LTR) ansetzen.');
  } else if (qgisVer === 'qgis_3_28_or_older' || qgisVer.includes('3.28')) {
    score -= 3;
    riskFactors.push('QGIS-Version <= 3.28 LTR: Überholte Datenbankschnittstellen und veraltetes Plugin-System.');
  }

  // GDI Komponenten (Sicherer Array-Check)
  if (gdiComp.includes('postgis')) {
    recommendations.push('PostGIS-Verbindungen und Datentypen-Handling auf QGIS 4 / GDAL 3.8+ Standards testen.');
  }
  if (gdiComp.includes('sap')) {
    score -= 3;
    riskFactors.push('SAP/ERP-Schnittstelle vorhanden: Kopplung von Sachdaten erfordert erweiterte Integrationstests.');
    recommendations.push('Schnittstellen-Audit für ERP-Kopplung durchführen.');
  }
  if (gdiComp.includes('wfs_wms')) {
    recommendations.push('Überprüfung der OGC-Webservices (WFS/WMS) auf Strict-Schema-Validation in QGIS 4.');
  }

  // Python & Custom Plugins
  if (hasPython === 'yes' || hasPython === 'ja' || hasPython.includes('ja')) {
    score -= 4;
    riskFactors.push('Eigene Python-Skripte / Plugins im Einsatz: PyQGIS API-Anpassungen (Python 3.12+ / PyQt6) erforderlich.');
    recommendations.push('Code-Audit der bestehenden Python-Skripte / Plugins hinsichtlich PyQGIS 4 API-Changes.');
  }

  // Score Grenzen festlegen (0 - 20)
  score = Math.max(0, Math.min(20, score));

  // Risikostufe & Farbcodes
  let riskLevel = 'NIEDRIGES RISIKO / BEREIT FÜR MIGRATION';
  let riskColor = '#2f855a'; // Grün
  let riskBg = '#f0fff4';

  if (score < 10) {
    riskLevel = 'HOHES RISIKO / HANDLUNGSBEDARF';
    riskColor = '#c53030'; // Rot
    riskBg = '#fff5f5';
  } else if (score < 16) {
    riskLevel = 'MITTLERES RISIKO / VORBEREITUNG NÖTIG';
    riskColor = '#dd6b20'; // Orange
    riskBg = '#fffaf0';
  }

  // Fallbacks
  if (riskFactors.length === 0) {
    riskFactors.push('Keine kritischen System-Blocker identifiziert.');
  }
  if (recommendations.length === 0) {
    recommendations.push('Reguläre Teststellung mit QGIS 4.2 LTR durchführen.');
  }
  recommendations.push('Infrastruktur-Testumgebung für QGIS 4.2 LTR vor dem flächendeckenden Rollout aufbauen.');

  // 3. HTML GENERATION
  const riskFactorsListHtml = riskFactors.map(rf => `<li style="margin-bottom: 6px;">${rf}</li>`).join('');
  const recommendationsListHtml = recommendations.map(rec => `<li style="margin-bottom: 6px;">${rec}</li>`).join('');

  const anonymousTeaserHtml = `
    <div style="background: #f8fafc; border: 2px dashed #cbd5e1; border-radius: 10px; padding: 24px; text-align: center; margin-top: 20px;">
      <h4 style="margin: 0 0 10px 0; font-size: 16px; color: #0f172a;">🔒 Vollständigen 6-Punkte-Fahrplan freischalten</h4>
      <p style="margin: 0 0 16px 0; font-size: 14px; color: #475569; line-height: 1.5;">
        Die konkreten Handlungsempfehlungen, Schnittstellen-Tests und der Migrations-Fahrplan für Ihre IT- & Amtsleitung sind im offiziellen PDF-Dossier enthalten.
      </p>
      <a href="https://qgis-profi.de" target="_blank" style="display: inline-block; background: #0f172a; color: #ffffff; text-decoration: none; padding: 12px 24px; border-radius: 8px; font-weight: 600; font-size: 14px; box-shadow: 0 4px 12px rgba(15,23,42,0.15);">
        📄 Offizielles PDF-Dossier kostenlos anfordern
      </a>
    </div>
  `;

  const legalDisclaimerHtml = `
    <div style="margin-top: 30px; border-top: 1px solid #e2e8f0; padding-top: 12px; font-size: 10px; color: #94a3b8; line-height: 1.4; text-align: justify;">
      <strong>Hinweis & Haftungsausschluss:</strong> Dieser Migrations-Report stellt eine automatisierte, unverbindliche Ersteinschätzung auf Basis der von Ihnen angegebenen Systemparameter dar. Er ersetzt keine individuelle technische Detailanalyse oder Beratung vor Ort. Tobey GIS Consulting übernimmt keine Haftung für die Richtigkeit, Vollständigkeit oder für Schäden, die aus der Umsetzung der aufgetragene Empfehlungen entstehen.
    </div>
  `;

  const htmlPreview = `
  <div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; color: #0f172a; line-height: 1.5; padding: 10px;">
    <div style="text-align: left; margin-bottom: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 12px;">
      <span style="font-size: 12px; font-weight: 700; color: #0284c7; letter-spacing: 1px; text-transform: uppercase;">TOBEY GIS CONSULTING</span>
      <h2 style="margin: 4px 0 0 0; font-size: 22px; color: #0f172a;">QGIS 4.2 LTR Migrations-Audit Report</h2>
    </div>
    <div style="background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 12px 16px; margin-bottom: 20px; font-size: 13.5px;">
      <strong>Organisation:</strong> ${isAnonymous ? 'Anonyme Erstdiagnose' : userOrg}<br>
      <strong>Systemumgebung:</strong> ${seats} GIS-Arbeitsplatz/Arbeitsplätze (${os})
    </div>
    <div style="text-align: center; padding: 24px; background: ${riskBg}; border-radius: 12px; border: 1px solid ${riskColor}40; margin-bottom: 24px;">
      <span style="font-size: 11px; font-weight: 700; color: #475569; letter-spacing: 1.5px; text-transform: uppercase;">MIGRATIONS-BEREITSCHAFTS-SCORE</span>
      <h1 style="font-size: 42px; margin: 8px 0; color: #0f172a; font-weight: 800;">${score} / 20 <span style="font-size: 20px; color: #64748b;">Punkten</span></h1>
      <span style="background: ${riskColor}; color: white; padding: 6px 16px; border-radius: 20px; font-weight: 700; font-size: 12px; display: inline-block;">
        ${riskLevel}
      </span>
    </div>
    <h3 style="font-size: 16px; border-bottom: 1px solid #e2e8f0; padding-bottom: 6px; color: #0f172a;">1. IDENTIFIZIERTE RISIKOFAKTOREN</h3>
    <ul style="padding-left: 20px; color: #334155; font-size: 14px;">
      ${riskFactorsListHtml}
    </ul>
    <h3 style="font-size: 16px; border-bottom: 1px solid #e2e8f0; padding-bottom: 6px; margin-top: 24px; color: #0f172a;">2. HANDLUNGSEMPFEHLUNGEN FÜR DIE IT / AMTSLEITUNG</h3>
    ${isAnonymous ? anonymousTeaserHtml : `<ul style="padding-left: 20px; color: #334155; font-size: 14px;">${recommendationsListHtml}</ul>`}
    ${legalDisclaimerHtml}
  </div>
  `;

  // Erfolgsausgabe mit valid: true
  outputJson = {
    valid: true,
    audit_modus: auditMode,
    is_anonymous: isAnonymous,
    user_name: userName,
    user_email: userEmail,
    user_org: userOrg,
    user_role: userRole,
    operating_system: os,
    gis_seats: seats,
    score: score,
    risk_level: riskLevel,
    risk_factors: riskFactors,
    recommendations: recommendations,
    html_preview: htmlPreview
  };

} catch (error) {
  // Dead-Letter-Handling Vorbereitung bei hartem Crash
  outputJson = {
    valid: false,
    error_message: error.message,
    html_preview: "<div style='color: red; padding: 20px;'><strong>Fehler bei der Audit-Verarbeitung:</strong> Ungültige Eingabeparameter. Bitte Administrator kontaktieren.</div>"
  };
}

return { json: outputJson };
